INSERT INTO formations (id_formation, titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) SELECT gen_random_uuid(), v.* FROM (VALUES ('Augmenter les ventes grâce à l’IA', 'Formation sur l’utilisation de l’intelligence artificielle pour booster les ventes et optimiser la stratégie commerciale.', 3, 200000.00, 'entreprise', '2026-11-10', 25, '2026-02-13 12:34:01', '2026-02-18 23:44:04', NULL, E'--- OBJECTIFS ---\n• Comprendre l’impact de l’IA sur les ventes\n• Utiliser des outils IA pour analyser les données clients\n• Développer des stratégies commerciales basées sur les données\n• Optimiser la performance et la rentabilité\n\n--- OBJECTIFS DÉTAILLÉS ---\nInitier les participants à l’utilisation de l’IA pour booster les ventes et leur apprendre à mettre en place une stratégie commerciale intelligente.\n\n--- PRÉREQUIS ---\nConnaissances de base en marketing ou commerce souhaitées.\n\n--- CONTENU ---\nModule 1 : Introduction à l’IA appliquée au commerce\nModule 2 : Analyse des données clients avec IA\nModule 3 : Stratégies commerciales intelligentes\nModule 4 : Atelier pratique – Mise en œuvre d’une stratégie IA\n\n--- NIVEAU ---\nAvancé\n\n--- PUBLIC ---\nCommerciaux, responsables marketing, chefs d’entreprise et entrepreneurs.\n\n--- MÉTHODES ---\nCours interactifs, démonstrations, ateliers pratiques et études de cas.\n\n--- SUPPORTS ---\nOutils IA, logiciels CRM, supports PDF et slides.\n\n--- CERTIFICATION ---\nAttestation de participation remise par ISD Groupe', 'ba52f30c-c061-41b8-b0f7-afa6eca6fa76')) AS v(titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) WHERE NOT EXISTS (SELECT 1 FROM formations f WHERE f.titre = v.titre AND f.date_debut = v.date_debut::date);
